module median_filter (
    input [8:0] pixels, // 3x3 matrix represented as a 9-bit vector
    output reg [4:0] median // 5-bit output for the median value
);
    integer i, j;
    reg [4:0] alt_sorted [0:8]; // Array to hold alt_sorted values

    always @(*) begin
        // Copy input pixels to alt_sorted array
        for (i = 0; i < 9; i = i + 1) begin
            alt_sorted[i] = pixels[i];
        end

        // Simple bubble sort to sort the values
        for (i = 0; i < 9; i = i + 1) begin
            for (j = 0; j < 8 - i; j = j + 1) begin
                if (alt_sorted[j] > alt_sorted[j + 1]) begin
                    // Swap
                    {alt_sorted[j], alt_sorted[j + 1]} = {alt_sorted[j + 1], alt_sorted[j]};
                end
            end
        end

        // The median is the 5th element after sorting
        median = alt_sorted[4];
    end
endmodule
